exec('import json\nimport re\nimport unicodedata\nfrom pathlib import Path\nfrom urllib.request import Request, urlopen\nfrom bs4 import BeautifulSoup\n\nOUT = Path("data")\nOUT.mkdir(exist_ok=True)\n\nFUENTES = {\n    "primera": "https://raw.githubusercontent.com/openfootball/football.json/master/2025-26/es.1.json",\n    "segunda": "https://raw.githubusercontent.com/openfootball/football.json/master/2025-26/es.2.json",\n}\n\nFUENTES_RESULTADOS = {\n    "primera": [\n        "https://www.laliga.com/laliga-easports/resultados",\n        "https://www.laliga.com/laliga-easports/resultados/2025-26/jornada-{}",\n        "https://www.mundodeportivo.com/resultados/futbol/primera-division/2025-2026/jornada-{}",\n        "https://as.com/resultados/futbol/primera/2025_2026/jornada/regular_a_{}/",\n    ],\n    "segunda": [\n        "https://www.laliga.com/laliga-hypermotion/resultados",\n        "https://www.laliga.com/laliga-hypermotion/resultados/2025-26/jornada-{}",\n        "https://www.mundodeportivo.com/resultados/futbol/liga-segunda-division/2025-2026/jornada-{}",\n        "https://www.mundodeportivo.com/resultados/futbol/liga-segunda-division/jornada-{}",\n        "https://as.com/resultados/futbol/segunda/2025_2026/jornada/regular_a_{}/",\n    ],\n}\n\nALIAS_EXTRA = {\n    "primera": [\n        "Athletic Club", "Club Atletico de Madrid", "Atletico de Madrid",\n        "CA Osasuna", "RC Celta", "Celta de Vigo", "Deportivo Alaves",\n        "Elche CF", "FC Barcelona", "Getafe CF", "Girona FC", "Levante UD",\n        "RCD Espanyol de Barcelona", "RCD Mallorca", "Real Betis Balompie",\n        "Real Madrid CF", "Real Oviedo", "Real Sociedad de Futbol",\n        "Sevilla FC", "Valencia CF", "Villarreal CF", "Rayo Vallecano de Madrid",\n    ],\n    "segunda": [\n        "Albacete BP", "RC Deportivo", "R. Racing Club", "Real Sporting",\n        "R. Sociedad B", "Real Valladolid CF", "Cultural y Deportiva Leonesa",\n        "AD Ceuta FC", "UD Almeria", "UD Las Palmas", "CD Castellon",\n        "Cordoba CF", "Malaga CF", "Cadiz CF", "Granada CF", "Burgos CF",\n        "SD Huesca", "SD Eibar", "CD Mirandes", "CD Leganes", "FC Andorra",\n        "Real Zaragoza",\n    ],\n}\n\ndef descargar(url):\n    req = Request(url, headers={\n        "User-Agent": "Mozilla/5.0",\n        "Accept-Language": "es-ES,es;q=0.9,en;q=0.8",\n    })\n    return urlopen(req, timeout=35).read().decode("utf-8", errors="ignore")\n\ndef clean(x):\n    return re.sub(r"\\s+", " ", str(x or "")).strip()\n\ndef sin_acentos(x):\n    return unicodedata.normalize("NFKD", x).encode("ascii", "ignore").decode("ascii")\n\ndef normalizar(txt):\n    txt = sin_acentos(clean(txt).lower())\n    equivalencias = {\n        "club atletico de madrid": "atletico", "atletico de madrid": "atletico", "ath madrid": "atletico",\n        "athletic club": "athletic", "ath bilbao": "athletic", "athletic bilbao": "athletic",\n        "fc barcelona": "barcelona", "barca": "barcelona",\n        "real madrid cf": "real madrid", "real madrid": "real madrid",\n        "real sociedad de futbol": "sociedad", "real sociedad": "sociedad",\n        "real betis balompie": "betis", "real betis": "betis",\n        "rayo vallecano de madrid": "rayo", "rayo vallecano": "rayo",\n        "rcd espanyol de barcelona": "espanyol", "espanyol": "espanyol", "espanol": "espanyol",\n        "rcd mallorca": "mallorca", "deportivo alaves": "alaves", "ca osasuna": "osasuna",\n        "rc celta": "celta", "celta de vigo": "celta", "elche cf": "elche",\n        "getafe cf": "getafe", "girona fc": "girona", "levante ud": "levante",\n        "real oviedo": "oviedo", "sevilla fc": "sevilla", "valencia cf": "valencia",\n        "villarreal cf": "villarreal",\n        "albacete bp": "albacete", "albacete balompie": "albacete",\n        "rc deportivo": "deportivo", "deportivo la coruna": "deportivo",\n        "deportivo de la coruna": "deportivo", "deportivo coruna": "deportivo", "la coruna": "deportivo",\n        "r racing club": "racing", "racing santander": "racing", "racing de santander": "racing",\n        "real sporting": "sporting", "sporting gijon": "sporting", "sporting de gijon": "sporting",\n        "r sociedad b": "sociedad b", "real sociedad b": "sociedad b",\n        "real sociedad ii": "sociedad b", "real sociedad de futbol b": "sociedad b",\n        "cultural y deportiva leonesa": "cultural", "cultural leonesa": "cultural",\n        "real zaragoza": "zaragoza", "real valladolid cf": "valladolid", "real valladolid": "valladolid",\n        "fc andorra": "andorra", "andorra fc": "andorra",\n        "ad ceuta fc": "ceuta", "ad ceuta": "ceuta",\n        "ud almeria": "almeria", "ud las palmas": "las palmas",\n        "cd castellon": "castellon", "cordoba cf": "cordoba", "malaga cf": "malaga",\n        "cadiz cf": "cadiz", "granada cf": "granada", "burgos cf": "burgos",\n        "sd huesca": "huesca", "sd eibar": "eibar", "cd mirandes": "mirandes",\n        "cd leganes": "leganes",\n    }\n    for a, b in equivalencias.items():\n        txt = txt.replace(a, b)\n    for q in ["club de futbol", "club deportivo", "union deportiva", " real ", " cf ", " fc ", " ud ", " cd ", " sd ", " rcd ", " rc ", " r "]:\n        txt = (" " + txt + " ").replace(q, " ")\n    txt = re.sub(r"[^a-z0-9 ]+", " ", txt)\n    return clean(txt)\n\ndef equipo_nombre(equipo):\n    if isinstance(equipo, dict):\n        return clean(equipo.get("name", ""))\n    return clean(equipo)\n\ndef cargar_openfootball(nombre, url):\n    data = json.loads(descargar(url))\n    jornadas = {}\n    for match in data.get("matches", []):\n        nums = re.findall(r"\\d+", str(match.get("round", "")))\n        if not nums:\n            continue\n        jornada = int(nums[0])\n        score = match.get("score", {})\n        ft = score.get("ft", []) if isinstance(score, dict) else []\n        estado = "Programado"\n        resultado = ""\n        if isinstance(ft, list) and len(ft) == 2:\n            estado = "Jugado"\n            resultado = f"{ft[0]}-{ft[1]}"\n        partido = {\n            "fecha": clean(match.get("date", "")),\n            "hora": clean(match.get("time", "")),\n            "local": equipo_nombre(match.get("team1")),\n            "visitante": equipo_nombre(match.get("team2")),\n            "estado": estado,\n            "resultado": resultado,\n        }\n        if partido["local"] and partido["visitante"]:\n            jornadas.setdefault(jornada, []).append(partido)\n    if not jornadas:\n        raise SystemExit(f"ERROR: calendario {nombre} vacio")\n    return jornadas\n\ndef construir_regex_equipos(jornadas, tipo):\n    equipos = set(ALIAS_EXTRA.get(tipo, []))\n    for partidos in jornadas.values():\n        for p in partidos:\n            equipos.add(p["local"])\n            equipos.add(p["visitante"])\n    return "|".join(sorted(map(re.escape, equipos), key=len, reverse=True))\n\ndef aplicar_dato(jornadas, jornada, local_web, visitante_web, resultado="", hora=""):\n    nl, nv = normalizar(local_web), normalizar(visitante_web)\n    resultado = clean(resultado).replace(" ", "")\n    hora = clean(hora)\n    for p in jornadas.get(jornada, []):\n        pl, pv = normalizar(p["local"]), normalizar(p["visitante"])\n        mismo = (pl in nl or nl in pl) and (pv in nv or nv in pv)\n        inverso = (pl in nv or nv in pl) and (pv in nl or nl in pv)\n        if not mismo and not inverso:\n            continue\n        if hora and not p.get("hora"):\n            p["hora"] = hora\n        if resultado and not p.get("resultado"):\n            if inverso:\n                goles = resultado.split("-")\n                resultado = f"{goles[1]}-{goles[0]}" if len(goles) == 2 else resultado\n            p["resultado"] = resultado\n            p["estado"] = "Jugado"\n        return True\n    return False\n\ndef reforzar_resultados_y_horas(tipo, jornadas):\n    equipos_re = construir_regex_equipos(jornadas, tipo)\n    patrones = [\n        re.compile(rf"({equipos_re})\\s+(\\d+)\\s*-\\s*(\\d+)\\s+({equipos_re})", re.I),\n        re.compile(rf"({equipos_re})\\s+(\\d+\\s*-\\s*\\d+)\\s+({equipos_re})", re.I),\n        re.compile(rf"(\\d{{1,2}}:\\d{{2}})\\s+({equipos_re})\\s+({equipos_re})", re.I),\n        re.compile(rf"({equipos_re})\\s+({equipos_re})\\s+(\\d{{1,2}}:\\d{{2}})", re.I),\n    ]\n    for jornada in sorted(jornadas):\n        anadidos = 0\n        for plantilla in FUENTES_RESULTADOS[tipo]:\n            url = plantilla.format(jornada) if "{}" in plantilla else plantilla\n            try:\n                html = descargar(url)\n            except Exception as e:\n                print(f"WARNING {tipo} J{jornada}: no leida {url}: {e}")\n                continue\n            texto = clean(BeautifulSoup(html, "html.parser").get_text(" "))\n            for patron in patrones:\n                for m in patron.finditer(texto):\n                    grupos = m.groups()\n                    if len(grupos) == 4 and re.match(r"\\d{1,2}:\\d{2}", grupos[0]):\n                        hora, local, visitante = grupos\n                        if aplicar_dato(jornadas, jornada, local, visitante, hora=hora):\n                            anadidos += 1\n                    elif len(grupos) == 4:\n                        local, g1, g2, visitante = grupos\n                        if aplicar_dato(jornadas, jornada, local, visitante, resultado=f"{g1}-{g2}"):\n                            anadidos += 1\n                    elif len(grupos) == 3 and re.match(r"\\d{1,2}:\\d{2}", grupos[2]):\n                        local, visitante, hora = grupos\n                        if aplicar_dato(jornadas, jornada, local, visitante, hora=hora):\n                            anadidos += 1\n                    elif len(grupos) == 3:\n                        local, resultado, visitante = grupos\n                        if aplicar_dato(jornadas, jornada, local, visitante, resultado=resultado):\n                            anadidos += 1\n        pendientes = [p for p in jornadas[jornada] if not p.get("resultado")]\n        print(f"{tipo} J{jornada}: datos anadidos {anadidos}, pendientes {len(pendientes)}")\n\ndef recalcular_clasificacion(jornadas):\n    tabla = {}\n    def asegurar(equipo):\n        if equipo not in tabla:\n            tabla[equipo] = {"equipo": equipo, "puntos": 0, "partidos": 0, "gf": 0, "gc": 0, "dg": 0, "ganados": 0, "empatados": 0, "perdidos": 0}\n    for partidos in jornadas.values():\n        for p in partidos:\n            resultado = clean(p.get("resultado", ""))\n            if not re.match(r"^\\d+\\-\\d+$", resultado):\n                continue\n            local, visitante = p["local"], p["visitante"]\n            gl, gv = map(int, resultado.split("-"))\n            asegurar(local); asegurar(visitante)\n            tabla[local]["partidos"] += 1; tabla[visitante]["partidos"] += 1\n            tabla[local]["gf"] += gl; tabla[local]["gc"] += gv\n            tabla[visitante]["gf"] += gv; tabla[visitante]["gc"] += gl\n            if gl > gv:\n                tabla[local]["puntos"] += 3; tabla[local]["ganados"] += 1; tabla[visitante]["perdidos"] += 1\n            elif gl < gv:\n                tabla[visitante]["puntos"] += 3; tabla[visitante]["ganados"] += 1; tabla[local]["perdidos"] += 1\n            else:\n                tabla[local]["puntos"] += 1; tabla[visitante]["puntos"] += 1\n                tabla[local]["empatados"] += 1; tabla[visitante]["empatados"] += 1\n    equipos = list(tabla.values())\n    for e in equipos:\n        e["dg"] = e["gf"] - e["gc"]\n    equipos.sort(key=lambda x: (x["puntos"], x["dg"], x["gf"]), reverse=True)\n    for i, e in enumerate(equipos, 1):\n        e["posicion"] = i\n    return equipos\n\ndef escribir_calendario(nombre, fuente, jornadas):\n    salida = {"competicion": nombre, "fuente": fuente, "jornadas": [{"jornada": j, "partidos": jornadas[j]} for j in sorted(jornadas)]}\n    Path(f"data/calendario_{nombre}.json").write_text(json.dumps(salida, ensure_ascii=False, indent=2), encoding="utf-8")\n    print(f"Calendario {nombre}: {len(jornadas)} jornadas generadas")\n\nprimera = cargar_openfootball("primera", FUENTES["primera"])\nsegunda = cargar_openfootball("segunda", FUENTES["segunda"])\nreforzar_resultados_y_horas("primera", primera)\nreforzar_resultados_y_horas("segunda", segunda)\nescribir_calendario("primera", FUENTES["primera"], primera)\nescribir_calendario("segunda", FUENTES["segunda"], segunda)\nclasificaciones = {"primera": recalcular_clasificacion(primera), "segunda": recalcular_clasificacion(segunda)}\nPath("clasificaciones.json").write_text(json.dumps(clasificaciones, ensure_ascii=False, indent=2), encoding="utf-8")\nprint("Clasificaciones recalculadas desde calendarios")\nprint("Calendarios generados correctamente")\n')
